.container {
width: 1190px;
/* 页面水平居中 */
margin: 0 auto;
}

/* 顶部导航条 start */
.topbar {
height: 30px;
background-color: #ececec;
}

.welcome {
height: 30px;
line-height: 30px;
font-size: 0;
color: #666;
}

.welcome span, .welcome a {
font-size: 12px;
}

.welcome .hello {
margin-right: 28px;
}

.welcome .login {
/* 用padding是因为margin在border外面，对border不生效 */
padding-right: 10px;
border-right: 1px solid #666;
}

.welcome .register {
padding-left: 10px;
}

/* 在div内垂直居中 */
.topbar-nav ul {
height: 30px;
line-height: 30px;
}

.topbar-nav ul&gt;li {
/* display: inline-block; 应改用浮动（左）*/
/* 垂直居中应找父元素ul定义 */
float: left;
}

.topbar-nav ul&gt;li&gt;a {
padding: 0 15px;
border-right: 1px solid #666;
}

.topbar-nav ul&gt;li:first-child a {
padding-left: 0;
}

.topbar-nav ul&gt;li:last-child a{
border-style: none;
padding-right: 0;
}
</code></pre>

